SELECT c.id AS id, c.name AS name, c.denomination AS denomination, c.region_id AS region_id, r.name AS region_name, c.address AS address, c.phone AS phone, c.pastor_name AS pastor_name, c.latitude AS latitude, c.longitude AS longitude, c.thumbnail_key AS thumbnail_key, c.data_source AS data_source, c.open_yn AS open_yn, c.use_yn AS use_yn, c.created_at AS created_at FROM CHURCH c LEFT JOIN REGION r ON c.region_id = r.id
AND c.use_yn = #{useYn}
ORDER BY c.created_at DESC, c.id DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM CHURCH c



        AND c.use_yn = #{useYn}

SELECT c.id AS id, c.name AS name, c.denomination AS denomination, c.region_id AS region_id, r.name AS region_name, c.address AS address, c.phone AS phone, c.pastor_name AS pastor_name, c.facilities AS facilities, c.latitude AS latitude, c.longitude AS longitude, c.thumbnail_key AS thumbnail_key, c.data_source AS data_source FROM CHURCH c LEFT JOIN REGION r ON c.region_id = r.id
AND c.use_yn = 'Y'
ORDER BY c.created_at DESC, c.id DESC LIMIT #{offset}, #{size}
